import pandas as pd, ast
cf=pd.read_csv('/work/wind_profile_20260612_215027.csv')['value'].apply(lambda x: ast.literal_eval(x)['electricity']).to_numpy()
# max consecutive zero and below thresholds
for thr in [0,0.01,0.02,0.05,0.1]:
    max_run=run=0
    end_idx=-1
    for i,v in enumerate(cf):
        if v<=thr:
            run +=1
            if run>max_run:
                max_run=run; end_idx=i
        else:
            run=0
    print('thr',thr,'max_run',max_run,'ending at',end_idx)
